2178	        if (sendSet) {
2179	            // Send data
2180	            auto [bytes_sent, data_left] = WITH_LOCK(pnode->cs_vSend, return SocketSendData(*pnode));
2181	            if (bytes_sent) {
2182	                RecordBytesSent(bytes_sent);
2183	
2184	                // If both receiving and (non-optimistic) sending were possible, we first attempt
2185	                // sending. If that succeeds, but does not fully drain the send queue, do not
2186	                // attempt to receive. This avoids needlessly queueing data if the remote peer
2187	                // is slow at receiving data, by means of TCP flow control. We only do this when
2188	                // sending actually succeeded to make sure progress is always made; otherwise a
2189	                // deadlock would be possible when both sides have data to send, but neither is
2190	                // receiving.
2191	                if (data_left) recvSet = false;
2192	            }
2193	        }
2194	
2195	        if (recvSet || errorSet)
2196	        {
2197	            // typical socket buffer is 8K-64K
2198	            uint8_t pchBuf[0x10000];
2199	            int nBytes = 0;
2200	            {
2201	                LOCK(pnode->m_sock_mutex);
2202	                if (!pnode->m_sock) {
2203	                    continue;
2204	                }
2205	                nBytes = pnode->m_sock->Recv(pchBuf, sizeof(pchBuf), MSG_DONTWAIT);
2206	            }
2207	            if (nBytes > 0)
2208	            {
2209	                bool notify = false;
2210	                if (!pnode->ReceiveMsgBytes({pchBuf, (size_t)nBytes}, notify)) {
2211	                    LogDebug(BCLog::NET,
2212	                        "receiving message bytes failed, %s",
2213	                        pnode->DisconnectMsg()
2214	                    );
2215	                    pnode->CloseSocketDisconnect();
2216	                }
2217	                RecordBytesRecv(nBytes);
2218	                if (notify) {
2219	                    pnode->MarkReceivedMsgsForProcessing();
2220	                    WakeMessageHandler();
2221	                }
2222	            }
2223	            else if (nBytes == 0)
2224	            {
2225	                // socket closed gracefully
2226	                if (!pnode->fDisconnect) {
2227	                    LogDebug(BCLog::NET, "socket closed, %s", pnode->DisconnectMsg());
2228	                }
2229	                pnode->CloseSocketDisconnect();
2230	            }
2231	            else if (nBytes < 0)
2232	            {
2233	                // error
2234	                int nErr = WSAGetLastError();
2235	                if (nErr != WSAEWOULDBLOCK && nErr != WSAEMSGSIZE && nErr != WSAEINTR && nErr != WSAEINPROGRESS)
2236	                {
2237	                    if (!pnode->fDisconnect) {
2238	                        LogDebug(BCLog::NET, "socket recv error, %s: %s", pnode->DisconnectMsg(), NetworkErrorString(nErr));
2239	                    }
2240	                    pnode->CloseSocketDisconnect();
2241	                }
2242	            }
2243	        }
2244	
2245	        if (InactivityCheck(*pnode, now)) pnode->fDisconnect = true;
2246	    }
