782	int V1Transport::readData(std::span<const uint8_t> msg_bytes)
783	{
784	    AssertLockHeld(m_recv_mutex);
785	    unsigned int nRemaining = hdr.nMessageSize - nDataPos;
786	    unsigned int nCopy = std::min<unsigned int>(nRemaining, msg_bytes.size());
787	
788	    if (vRecv.size() < nDataPos + nCopy) {
789	        // Allocate up to 256 KiB ahead, but never more than the total message size.
790	        vRecv.resize(std::min(hdr.nMessageSize, nDataPos + nCopy + 256 * 1024));
791	    }
792	
793	    hasher.Write(msg_bytes.first(nCopy));
794	    memcpy(&vRecv[nDataPos], msg_bytes.data(), nCopy);
795	    nDataPos += nCopy;
796	
797	    return nCopy;
798	}
