1489	bool V2Transport::SetMessageToSend(CSerializedNetMsg& msg) noexcept
1490	{
1491	    AssertLockNotHeld(m_send_mutex);
1492	    LOCK(m_send_mutex);
1493	    if (m_send_state == SendState::V1) return m_v1_fallback.SetMessageToSend(msg);
1494	    // We only allow adding a new message to be sent when in the READY state (so the packet cipher
1495	    // is available) and the send buffer is empty. This limits the number of messages in the send
1496	    // buffer to just one, and leaves the responsibility for queueing them up to the caller.
1497	    if (!(m_send_state == SendState::READY && m_send_buffer.empty())) return false;
1498	    // Construct contents (encoding message type + payload).
1499	    std::vector<uint8_t> contents;
1500	    auto short_message_id = V2_MESSAGE_MAP(msg.m_type);
1501	    if (short_message_id) {
1502	        contents.resize(1 + msg.data.size());
1503	        contents[0] = *short_message_id;
1504	        std::copy(msg.data.begin(), msg.data.end(), contents.begin() + 1);
1505	    } else {
1506	        // Initialize with zeroes, and then write the message type string starting at offset 1.
1507	        // This means contents[0] and the unused positions in contents[1..13] remain 0x00.
1508	        contents.resize(1 + CMessageHeader::MESSAGE_TYPE_SIZE + msg.data.size(), 0);
1509	        std::copy(msg.m_type.begin(), msg.m_type.end(), contents.data() + 1);
1510	        std::copy(msg.data.begin(), msg.data.end(), contents.begin() + 1 + CMessageHeader::MESSAGE_TYPE_SIZE);
1511	    }
1512	    // Construct ciphertext in send buffer.
1513	    m_send_buffer.resize(contents.size() + BIP324Cipher::EXPANSION);
1514	    m_cipher.Encrypt(MakeByteSpan(contents), {}, false, MakeWritableByteSpan(m_send_buffer));
1515	    m_send_type = msg.m_type;
1516	    // Release memory
1517	    ClearShrink(msg.data);
1518	    return true;
1519	}

